}

// Updated State Machine
type ShipState = 'INTRO' | 'COUNTDOWN' | 'PLANNING' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'RETURNING' | 'SUMMARY';

// --- VISUAL COMPONENTS ---

const WarpEffect = ({ speed, isActive }: { speed: number, isActive: boolean }) => {
  // Only show warp effect when moving fast
  const opacity = isActive && speed > 15 ? 0.6 : 0;

  return (
    <group rotation={[Math.PI / 2, 0, 0]} position={[0, 0, -5]}>
      {/* Long streaks for warp speed sensation */}
      <Sparkles 
        count={200} 
        scale={[12, 12, 60]} 
        size={speed > 20 ? 15 : 6} 
        speed={speed * 0.2} 
        opacity={opacity} 
        color="#00ffff"
        noise={0.2}
      />
      {/* Secondary particles */}
      <Sparkles 
        count={100} 
        scale={[8, 8, 40]} 
        size={3} 
        speed={speed * 0.15} 
        opacity={opacity * 0.5} 
        color="#ffffff" 
      />
    </group>
  );
};

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // UI State
  const [uiState, setUiState] = useState<'INTRO' | 'COUNTDOWN' | 'ACTIVE' | 'SUMMARY'>('INTRO');
  const [countdownVal, setCountdownVal] = useState(3);
  const [missionLog, setMissionLog] = useState<string[]>([]);

  // Logic Refs
  const stateRef = useRef<ShipState>('INTRO');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // Movement calculation refs
  const currentSpeedRef = useRef(0);
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const camDistRef = useRef(16); 

  // Leaving/Transition Refs
  const exitVectorRef = useRef(new Vector3());
  const leavingTimeRef = useRef(0);

  // Constants
  const MAX_SPEED = 28; 
  const ORBIT_SPEED = 8; 

  // --- LOGIC HELPERS ---

  const generateMission = () => {
     // Exclude Sun and Mercury for this random tour (optional preference)
     const candidates = PLANETS
        .filter(p => p.id !== 'mercury')
        .map(p => p.id);

     const mission: string[] = [];
     let lastPlanet = 'earth'; 

     // Pick 4 random destinations (shorter for kids)
     for (let i = 0; i < 4; i++) {
        let next: string;
        let attempts = 0;
        do {
            next = candidates[Math.floor(Math.random() * candidates.length)];
            attempts++;
        } while (next === lastPlanet && attempts < 10);

        mission.push(next);
        lastPlanet = next;
     }

     return mission;
  };

  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12; 
     if (p.hasRings) return p.size * 2.5 + 2.0; 
     return p.size * 2.8 + 2.0; 
  };

  // --- USER INTERACTIONS ---

  const startLaunch = () => {
    setUiState('COUNTDOWN');
    setCountdownVal(3);

    let count = 3;
    const interval = setInterval(() => {
        count--;
        if (count > 0) {
            setCountdownVal(count);
        } else {
            clearInterval(interval);
            setUiState('ACTIVE');
            stateRef.current = 'PLANNING'; // Start the logic machine
        }
    }, 1000);
  };

  const finishMission = () => {
      onMissionComplete();
  };

  // --- RENDER LOOP ---

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // 0. INITIALIZATION: Spawn docked at Earth
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        if (startPos.lengthSq() > 1) { 
             // Park slightly above/away from Earth
             startPos.y += 4.0; 
             startPos.z += 8.0; 
             startPos.x += 8.0;

             groupRef.current.position.copy(startPos);

             // Look at Earth initially
             const earthPos = new Vector3();
             earthObj.getWorldPosition(earthPos);
             groupRef.current.lookAt(earthPos);

             initializedRef.current = true;
             // Stay in INTRO state until user clicks Launch
        }
      }
      return; 
    }

    // If waiting for user, just hover gently
    if (stateRef.current === 'INTRO') {
        groupRef.current.position.y += Math.sin(state.clock.elapsedTime) * 0.01;
        // Slowly rotate ship
        if(shipModelRef.current) shipModelRef.current.rotation.z = Math.sin(state.clock.elapsedTime * 0.5) * 0.05;
        return;
    }

    // --- FLIGHT STATE MACHINE ---

    // PLANNING: Generate Route
    if (stateRef.current === 'PLANNING') {
       const mission = generateMission();
       missionQueueRef.current = [...mission]; // Copy for logic

       // Store full mission log for display (Planets + Return to Earth)
       const names = mission.map(id => PLANETS.find(p => p.id === id)?.name || id);
       setMissionLog(names);

       stateRef.current = 'LEAVING'; 

       // Setup initial exit vector: Turn away from Earth to start journey
       // Simple hack: Assume (0,0,0) is Sun, fly away from center generally
       const awayFromCenter = groupRef.current.position.clone().normalize();
       exitVectorRef.current.copy(awayFromCenter);

       leavingTimeRef.current = 0;
       return;
    }

    // LEAVING / TRANSITION
    if (stateRef.current === 'LEAVING') {
       leavingTimeRef.current += delta;

       // Accelerate
       currentSpeedRef.current += (MAX_SPEED - currentSpeedRef.current) * 1.5 * delta;

       // Move
       const moveVec = exitVectorRef.current.clone().multiplyScalar(currentSpeedRef.current * delta);
       groupRef.current.position.add(moveVec);

       // Rotate Ship towards vector
       const lookTarget = groupRef.current.position.clone().add(exitVectorRef.current);
       const dummy = new Object3D();
       dummy.position.copy(groupRef.current.position);
       dummy.lookAt(lookTarget);
       groupRef.current.quaternion.slerp(dummy.quaternion, 2 * delta);

       // Select next target after clearing orbit
       if (leavingTimeRef.current > 1.5) {
          if (missionQueueRef.current.length > 0) {
             currentTargetIdRef.current = missionQueueRef.current.shift()!;
             stateRef.current = 'TRAVELING';
          } else {
             // Mission done, return to Earth
             currentTargetIdRef.current = 'earth';
             stateRef.current = 'RETURNING';
          }
       }
    }

    // RETURNING: Special travel state for final leg
    if (stateRef.current === 'RETURNING') {
        // Same logic as traveling, but logic switch at end
        // Reuse traveling logic for movement, but we check targetID inside Loop
        stateRef.current = 'TRAVELING'; 
        // We'll catch the arrival in TRAVELING block logic
    }

    // COMPLETED / SUMMARY
    if (stateRef.current === 'SUMMARY') {
        // Just hover/orbit gently around Earth
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, 0, delta);
        if(shipModelRef.current) shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta);
        return;
    }

    // Common Target Logic
    let targetObj: Object3D | null = null;
    let targetPos = new Vector3();
    const tId = currentTargetIdRef.current;

    if (tId && planetRefs.current[tId]) {
      targetObj = planetRefs.current[tId];
      targetObj.getWorldPosition(targetPos);
    } 

    const currentPos = groupRef.current.position.clone();

    // TRAVELING: Fly towards planet
    if (stateRef.current === 'TRAVELING' && targetObj) {
      const targetRadius = getSafeOrbitRadius(tId!);

      const dirToPlanet = new Vector3().subVectors(targetPos, currentPos).normalize();

      // Aim for orbit entry point
      const flatDir = new Vector3(dirToPlanet.x, 0, dirToPlanet.z).normalize();
      const entryPoint = new Vector3(
          targetPos.x - flatDir.x * targetRadius,
          targetPos.y, 
          targetPos.z - flatDir.z * targetRadius
      );

      const distToEntry = currentPos.distanceTo(entryPoint);

      // Speed Management
      let targetSpeed = MAX_SPEED;
      if (distToEntry < 40) targetSpeed = ORBIT_SPEED; // Slow down earlier

      currentSpeedRef.current += (targetSpeed - currentSpeedRef.current) * 2.0 * delta;

      if (distToEntry < 3) {
         // Arrived
         if (tId === 'earth' && missionQueueRef.current.length === 0) {
             // Really back home
             stateRef.current = 'SUMMARY';
             setUiState('SUMMARY');
             currentSpeedRef.current = 0; // Stop
         } else {
             stateRef.current = 'ORBITING';
             orbitRadiusRef.current = targetRadius;
             const relativePos = new Vector3().subVectors(currentPos, targetPos);
             orbitAngleRef.current = Math.atan2(relativePos.z, relativePos.x);
             totalOrbitTraveledRef.current = 0;
         }
      } else {
         // Move
         const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();
         groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

         // Rotate Ship
         const lookPos = currentPos.clone().add(moveDir);
         const slerpSpeed = distToEntry < 10 ? 3 * delta : 5 * delta;
         const dummyObj = new Object3D();
         dummyObj.position.copy(currentPos);
         dummyObj.lookAt(lookPos);
         groupRef.current.quaternion.slerp(dummyObj.quaternion, slerpSpeed);

         // Bank effect
         if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
         }
      }
    }

    // ORBITING
    if (stateRef.current === 'ORBITING' && targetObj) {
       currentSpeedRef.current += (ORBIT_SPEED - currentSpeedRef.current) * 2.0 * delta;

       const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
       const angleDelta = angularSpeed * delta;

       orbitAngleRef.current += angleDelta;
       totalOrbitTraveledRef.current += angleDelta;

       const nextX = targetPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextZ = targetPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextY = targetPos.y; 

       const nextPos = new Vector3(nextX, nextY, nextZ);
       groupRef.current.position.copy(nextPos);

       // Look along tangent
       const futureAngle = orbitAngleRef.current + 0.1;
       const lookX = targetPos.x + Math.cos(futureAngle) * orbitRadiusRef.current;
       const lookZ = targetPos.z + Math.sin(futureAngle) * orbitRadiusRef.current;

       const lookAtPos = new Vector3(lookX, targetPos.y, lookZ);
       const dummyObj = new Object3D();
       dummyObj.position.copy(nextPos);
       dummyObj.lookAt(lookAtPos);
       groupRef.current.quaternion.slerp(dummyObj.quaternion, 8 * delta);

       // Bank
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 4, delta * 3);
       }

       // 1 full orbit then leave
       if (totalOrbitTraveledRef.current > Math.PI * 2) {
          stateRef.current = 'LEAVING';
          const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
          exitVectorRef.current.copy(forward);
          leavingTimeRef.current = 0;
       }
    }

    // --- CAMERA LOGIC ---
    const targetCamDist = (stateRef.current === 'ORBITING' || stateRef.current === 'INTRO' || stateRef.current === 'SUMMARY') ? 22 : 14;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta * 2.0);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();

    // In INTRO/SUMMARY, rotate camera around ship slowly
    let camOffset;
    if (stateRef.current === 'INTRO' || stateRef.current === 'SUMMARY') {
        const time = state.clock.elapsedTime * 0.2;
        camOffset = new Vector3(Math.sin(time) * 20, 8, Math.cos(time) * 20);
    } else {
        const heightOffset = MathUtils.lerp(4, 8, (camDistRef.current - 14) / (22 - 14));
        camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    }

    const desiredCamPos = groupRef.current.position.clone().add(camOffset);
    state.camera.position.lerp(desiredCamPos, 0.1);

    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(5));
    state.camera.lookAt(lookTarget);
  });

