        50% { transform: scale(1.05); opacity: 1; }
        100% { transform: scale(0.95); opacity: 0.5; }
    }
  `;

  return (
    <>
      <Html>
        <style>{overlayStyle}</style>
      </Html>

      {/* 3D SHIP MODEL */}
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* HUD Overlay - Only when Active */}
        {uiState === 'ACTIVE' && (
            <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
                <div className="flex flex-col items-start pointer-events-none select-none gap-2">
                    {/* Simplified HUD for kids */}
                    <div className="bg-cyan-900/60 border-l-4 border-cyan-400 backdrop-blur-md px-4 py-2 rounded-r-xl transform skew-x-[-6deg]">
                        <span className="text-[10px] text-cyan-200 font-bold uppercase tracking-widest block">Speed</span>
                        <div className="flex items-end gap-1">
                            <span className="text-2xl font-black text-white font-mono">{Math.round(currentSpeedRef.current * 100)}</span>
                            <span className="text-xs text-cyan-300 font-bold mb-1">km/h</span>
