            </Html>
        )}

        {/* Warp Effect Component - Local to Ship */}
        <WarpEffect speed={currentSpeedRef.current} isActive={uiState === 'ACTIVE'} />

        {/* Inner Ship Model */}
        <group ref={shipModelRef}>
            <group rotation={[Math.PI / 2, 0, 0]}>
