                {/* Glowing Text */}
                <group position={[0, 0, 0.36]}>
                     <Text color="white" fontSize={0.25} anchorX="center" anchorY="middle" outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* Nose Cone */}
                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial color="#cbd5e1" metalness={0.8} roughness={0.2} />
                </mesh>

                {/* Wings */}
                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#334155" />
                   </mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#334155" />
                   </mesh>
                </group>

                {/* Engines */}
                <group position={[0, -0.85, 0]}>
                   <mesh><cylinderGeometry args={[0.25, 0.2, 0.1, 16]} /><meshStandardMaterial color="#0f172a" /></mesh>
                </group>

                {/* Engine Flame - Dynamic Scale based on Speed */}
                <mesh position={[0, -1.6, 0]} scale={[1, 1 + currentSpeedRef.current * 0.05, 1]}>
                  <cylinderGeometry args={[0.15, 0.0, 1.4, 16, 1, true]} /> 
                  <meshBasicMaterial color="#38bdf8" transparent opacity={0.6} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
                 <mesh position={[0, -1.2, 0]} scale={[1, 1 + currentSpeedRef.current * 0.03, 1]}>
                  <cylinderGeometry args={[0.08, 0.0, 0.8, 8, 1, true]} /> 
                  <meshBasicMaterial color="#ffffff" transparent opacity={0.9} depthWrite={false} blending={AdditiveBlending} />
                </mesh>

                <pointLight position={[0, -1, 0]} color="#0ea5e9" distance={5} intensity={3 + currentSpeedRef.current * 0.1} />
            </group>

            {/* Blue Trail */}
            <group position={[0, 0, -1.2]}>
              <Trail width={0.6} length={8} color="#0ea5e9" attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
        </group>
      </group>

      {/* --- 2D UI OVERLAYS --- */}

      {/* 1. INTRO SCREEN */}
      {uiState === 'INTRO' && (
         <Html center fullscreen zIndexRange={[1000, 1000]}>
            <div className="w-full h-full flex items-center justify-center bg-black/60 backdrop-blur-sm pointer-events-auto">
                <div className="scifi-panel p-8 rounded-3xl max-w-md text-center flex flex-col items-center animate-pop-up">
                    <div className="text-6xl mb-4">🚀</div>
                    <h1 className="text-3xl font-black text-white italic tracking-wider mb-2" style={{fontFamily: '"ZCOOL KuaiLe", cursive'}}>
                        星际穿越模式
                    </h1>
                    <p className="text-cyan-200 text-lg mb-6">
                        小豆子船长，飞船已整装待发！<br/>准备好去探索未知的星球了吗？
                    </p>
                    <button 
                        onClick={startLaunch}
                        className="scifi-btn text-xl font-bold px-10 py-4 rounded-xl cursor-pointer"
                    >
