            </div>
         </Html>
      )}

      {/* 2. COUNTDOWN */}
      {uiState === 'COUNTDOWN' && (
         <Html center fullscreen zIndexRange={[1000, 1000]}>
             <div className="w-full h-full flex items-center justify-center pointer-events-none">
                 <div className="text-9xl font-black text-transparent bg-clip-text bg-gradient-to-b from-yellow-300 to-red-600 drop-shadow-[0_0_30px_rgba(255,100,0,0.8)] scale-150 animate-bounce">
                     {countdownVal}
                 </div>
             </div>
         </Html>
      )}

      {/* 3. SUMMARY SCREEN */}
      {uiState === 'SUMMARY' && (
          <Html center fullscreen zIndexRange={[1000, 1000]}>
             <div className="w-full h-full flex items-center justify-center bg-black/70 backdrop-blur-md pointer-events-auto">
                 <div className="scifi-panel p-8 rounded-3xl max-w-lg w-full text-center flex flex-col items-center relative overflow-hidden animate-pop-up border-2 border-yellow-400/50">
                     {/* Confetti Background Effect (CSS only simple version) */}
                     <div className="absolute inset-0 opacity-20 pointer-events-none" 
                          style={{backgroundImage: 'radial-gradient(#fbbf24 2px, transparent 2px)', backgroundSize: '30px 30px'}}>
                     </div>

                     <div className="text-6xl mb-2 animate-bounce">🏆</div>
                     <h2 className="text-4xl font-black text-yellow-400 italic tracking-wider mb-1" style={{fontFamily: '"ZCOOL KuaiLe", cursive'}}>
                         任务完成！
                     </h2>
                     <p className="text-gray-300 text-sm mb-6 uppercase tracking-widest">Mission Accomplished</p>

                     <div className="w-full bg-slate-800/50 rounded-xl p-4 mb-6 border border-white/10 text-left">
                         <h3 className="text-cyan-400 text-xs font-bold uppercase mb-3 border-b border-white/10 pb-1">本次探索日志</h3>
                         <ul className="space-y-2">
                             {missionLog.map((planet, idx) => (
                                 <li key={idx} className="flex items-center gap-2 text-white font-bold text-lg">
                                     <span className="text-cyan-500">✓</span> 
                                     {planet}
                                 </li>
                             ))}
                             <li className="flex items-center gap-2 text-green-400 font-bold text-lg border-t border-white/10 pt-2 mt-2">
                                 <span className="text-green-400">🏠</span> 
                                 安全返回地球
