import React, { useRef, useState, useEffect, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, Quaternion, MathUtils, Matrix4, AdditiveBlending } from 'three';
import { Trail, Html, Text, Sparkles } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
  isBoostActive: boolean;
  cameraMode: number; // 0: TPS (Chase), 1: Cockpit, 2: Drone (Cinematic)
}

// Visual: Speed lines that appear when flying fast
const WarpTunnel: React.FC<{ speed: number }> = ({ speed }) => {
  // Only show when fast
  if (speed < 40) return null;

  const count = 200;
  // Dynamic scale based on speed: Higher speed = longer lines
  const length = MathUtils.clamp(speed * 0.8, 20, 100);
  const opacity = MathUtils.clamp((speed - 40) / 60, 0, 0.6);

  return (
    <group>
       <Sparkles 
         count={count} 
         scale={[40, 40, 100]} // Long tunnel
         size={length} 
         speed={speed * 0.2} 
         opacity={opacity}
         color="#b3e5fc"
         noise={0.5}
       />
    </group>
  );
};

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete, isBoostActive, cameraMode }) => {
  const shipRef = useRef<Group>(null);
  const modelRef = useRef<Group>(null);
  const engineGlowRef = useRef<Group>(null);

  // Logic State
  const [targetId, setTargetId] = useState<string | null>(null);
  const [status, setStatus] = useState("引擎预热...");

  // Physics Refs (Mutable for performance, bypassing React state updates)
  const position = useRef(new Vector3(0, 20, 40)); 
  const velocity = useRef(new Vector3(0, 0, 0));
  const speedRef = useRef(0);
  const targetOrbitAngle = useRef(0);
  const missionQueue = useRef<string[]>([]);

  // Camera Physics Refs (Spring Arm)
  const cameraPosLag = useRef(new Vector3(0, 50, 80));
  const cameraLookLag = useRef(new Vector3(0, 0, 0));

  // Flight Parameters
  const MIN_SPEED = 30;
  const MAX_SPEED = 180; // Boost speed
  const ORBIT_SPEED = 25;
  const TURN_SPEED = 3.0; // How fast it steers
  const ORBIT_DISTANCE_MULTIPLIER = 3.0; 

  // --- MISSION PLANNER ---
  useEffect(() => {
    // 1. Generate a random tour path (Earth -> Random -> Random -> Earth)
    const candidates = PLANETS.filter(p => p.id !== 'sun' && p.id !== 'earth').map(p => p.id);

    // Shuffle candidates
    for (let i = candidates.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [candidates[i], candidates[j]] = [candidates[j], candidates[i]];
    }

    // Pick 3 planets then go back to Earth
    const queue = candidates.slice(0, 3);
    queue.push('earth');
    missionQueue.current = queue;

    // 2. Initial Spawn Position (Near Earth)
    if (planetRefs.current['earth']) {
        const earthPos = new Vector3();
        planetRefs.current['earth'].getWorldPosition(earthPos);
        // Start slightly offset
        position.current.copy(earthPos).add(new Vector3(0, 10, 30));
    }
  }, []);

  useFrame((state, delta) => {
    if (!shipRef.current) return;

    // --- 1. TARGET SYSTEM ---
    if (!targetId) {
        if (missionQueue.current.length > 0) {
            const next = missionQueue.current.shift()!;
            setTargetId(next);
            const pName = PLANETS.find(p => p.id === next)?.name.split(' ')[0];
            setStatus(`前往: ${pName}`);
        } else {
            // Refill queue if empty to keep flying forever
            const candidates = PLANETS.filter(p => p.id !== 'sun').map(p => p.id);
             for (let i = candidates.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [candidates[i], candidates[j]] = [candidates[j], candidates[i]];
            }
            missionQueue.current = candidates.slice(0, 3);
        }
        return;
    }

    const targetObj = planetRefs.current[targetId];
    if (!targetObj) return;

    const targetPos = new Vector3();
    targetObj.getWorldPosition(targetPos);

    // Calculate Orbit Radius based on planet size
    const pData = PLANETS.find(p => p.id === targetId);
    const planetSize = pData ? pData.size : 2;
    const orbitRadius = Math.max(planetSize * ORBIT_DISTANCE_MULTIPLIER + 8, 15);

    const distToTarget = position.current.distanceTo(targetPos);

    // --- 2. PHYSICS FLIGHT MODEL (Steering Behaviors) ---

    const isOrbiting = distToTarget < orbitRadius + 10;

    // Determine Desired Velocity
    const desiredVelocity = new Vector3();

    if (isOrbiting) {
        // --- ORBIT MODE: Fly tangent to the circle ---
        setStatus("环绕观测中...");

        // Calculate the vector from planet to ship
        const radiusVec = position.current.clone().sub(targetPos);
        radiusVec.y = 0; // Keep orbit flat-ish

        // Calculate tangent (Cross product with Up)
        const tangent = new Vector3(0, 1, 0).cross(radiusVec).normalize();

        desiredVelocity.copy(tangent).multiplyScalar(ORBIT_SPEED);

        // Pull slightly inward to maintain orbit (Centripetal force approximation)
        const correction = radiusVec.normalize().negate().multiplyScalar(5);
        desiredVelocity.add(correction);

        // Timer/Angle check to leave orbit
        targetOrbitAngle.current += delta;
        if (targetOrbitAngle.current > 8) { // After some time
            setTargetId(null); // Next target
            targetOrbitAngle.current = 0;
        }

    } else {
        // --- TRANSIT MODE: Seek Target ---

        // Direction to target
        const dirToTarget = targetPos.clone().sub(position.current).normalize();

        // Boost Logic
        const maxS = isBoostActive ? MAX_SPEED : MIN_SPEED;

        // Arrival slowing (very simple easing)
        let speed = maxS;
        if (distToTarget < orbitRadius + 80) {
            speed = MathUtils.lerp(speed, ORBIT_SPEED, 0.05); // Start braking
            setStatus("减速入轨...");
        } else if (isBoostActive) {
            setStatus(">>> 超光速推进 >>>");
        }

        desiredVelocity.copy(dirToTarget).multiplyScalar(speed);

        // Add some "Arc" to the path so it's not a straight boring line?
        // Ideally Boids steering handles smoothness naturally.
    }

    // STEERING FORCE: Steer = Desired - Current
    // We blend current velocity towards desired velocity for smooth turns
    const steerStrength = isOrbiting ? 4.0 : (isBoostActive ? 1.0 : 2.0); // Harder to turn when boosting
    velocity.current.lerp(desiredVelocity, delta * steerStrength);

    // Apply Velocity
    position.current.add(velocity.current.clone().multiplyScalar(delta));
    shipRef.current.position.copy(position.current);

    // Speed Calculation
    speedRef.current = velocity.current.length();

    // ROTATION: Face forward
    const lookTarget = position.current.clone().add(velocity.current);
    const dummy = new Object3D();
    dummy.position.copy(position.current);
    dummy.lookAt(lookTarget);
    shipRef.current.quaternion.slerp(dummy.quaternion, delta * 5.0);

    // BANKING (Roll): Roll based on horizontal turn
    if (modelRef.current) {
        // Calculate turn rate approximately by comparing current velocity direction with desired
        // Or simpler: use the side component of velocity relative to forward
        const localVel = velocity.current.clone().applyQuaternion(shipRef.current.quaternion.clone().invert());
        // localVel.x indicates slide. If we are turning left, localVel.x is positive? 
        // Actually, let's just use a simpler visual hack:
        // Roll based on Y rotation delta? 
        // Let's use noise for "turbulence" + speed based roll

        const turnRoll = -localVel.x * 0.05; // Bank into turn
        const turbulence = isBoostActive ? Math.sin(state.clock.elapsedTime * 20) * 0.15 : Math.sin(state.clock.elapsedTime) * 0.05;

        modelRef.current.rotation.z = MathUtils.lerp(modelRef.current.rotation.z, turnRoll + turbulence, delta * 3);
    }

    // Engine Glow Scale
    if (engineGlowRef.current) {
        const s = isBoostActive ? 4 : 1;
        const targetScale = new Vector3(s, s, s * 2.5);
        engineGlowRef.current.scale.lerp(targetScale, delta * 10);
    }


    // --- 3. CINEMATIC CAMERA SYSTEM ---

    // Calculate Ideal Camera Position & LookAt
    const shipPos = position.current;
    const shipQuat = shipRef.current.quaternion;
    const back = new Vector3(0, 0, -1).applyQuaternion(shipQuat).negate(); // Backward vector
    const up = new Vector3(0, 1, 0).applyQuaternion(shipQuat);

    let idealOffset = new Vector3();
    let idealLook = new Vector3();
    let targetFov = 45;

    if (cameraMode === 0) {
        // TPS (Chase)
        // Camera moves further back as speed increases
        const speedRatio = MathUtils.clamp(speedRef.current / MAX_SPEED, 0, 1);
        const camDist = 25 + speedRatio * 30; // 25 to 55 distance
        const camHeight = 8 + speedRatio * 5;

        idealOffset = back.clone().multiplyScalar(-camDist).add(up.clone().multiplyScalar(camHeight));
        idealLook = shipPos.clone().add(back.clone().multiplyScalar(50)); // Look far ahead

        // Dynamic FOV
        targetFov = 45 + speedRatio * 40; // 45 to 85 FOV

    } else if (cameraMode === 1) {
        // Cockpit (First Person)
        const speedRatio = MathUtils.clamp(speedRef.current / MAX_SPEED, 0, 1);
        idealOffset = back.clone().multiplyScalar(2.5).add(up.clone().multiplyScalar(0.8)); // Inside head position
        idealLook = shipPos.clone().add(back.clone().multiplyScalar(100));
        targetFov = 60 + speedRatio * 50; // Very wide when fast

    } else {
        // Drone (Orbiting Beauty Shot)
        const time = state.clock.elapsedTime * 0.3;
        const radius = 35;
        idealOffset = new Vector3(Math.cos(time) * radius, 15, Math.sin(time) * radius);
        idealLook = shipPos.clone();
        targetFov = 40;
    }

    // Camera Lag (Spring Arm)
    // We lerp the camera's CURRENT position towards the IDEAL position.
    // Lower factor = More lag (heavier feel). Higher factor = Snappier.
    const lagFactor = cameraMode === 1 ? 0.3 : 0.08; // Cockpit is snappier, TPS is loose

    // 1. Calculate World Position for Ideal Camera
    const desiredCamWorldPos = shipPos.clone().add(idealOffset);

    // 2. Smoothly move camera "Lag" vector towards desired
    cameraPosLag.current.lerp(desiredCamWorldPos, delta / lagFactor * 0.5); // Tune this for feel
    cameraLookLag.current.lerp(idealLook, delta * 5.0);

    // 3. Add Screen Shake
    const shakeIntensity = isBoostActive ? 0.5 : 0;
    const shake = new Vector3(
        (Math.random() - 0.5) * shakeIntensity,
        (Math.random() - 0.5) * shakeIntensity,
        (Math.random() - 0.5) * shakeIntensity
    );

    // 4. Apply to ThreeJS Camera
    state.camera.position.copy(cameraPosLag.current).add(shake);
    state.camera.lookAt(cameraLookLag.current);
    state.camera.fov = MathUtils.lerp(state.camera.fov, targetFov, delta * 2.0);
    state.camera.updateProjectionMatrix();

  });

  return (
    <group ref={shipRef} scale={[1.5, 1.5, 1.5]}>

      {/* Warp Visuals attached to ship space */}
      <WarpTunnel speed={speedRef.current} />

      {/* HUD Info floating above ship */}
      <Html position={[0, 3.5, 0]} center zIndexRange={[100, 0]} transform sprite>
         <div className="flex flex-col items-center pointer-events-none select-none opacity-90">
            <div className={`text-[10px] font-mono mb-1 tracking-widest uppercase px-2 rounded backdrop-blur-md border 
                ${isBoostActive ? 'bg-red-500/40 border-red-400 text-white animate-pulse' : 'bg-black/50 border-cyan-500/50 text-cyan-300'}`}>
               {status}
            </div>
            {/* Speed Bar */}
            <div className="w-24 h-1.5 bg-gray-800 rounded-full overflow-hidden border border-gray-600">
               <div 
                 className={`h-full transition-all duration-75 ${isBoostActive ? 'bg-gradient-to-r from-yellow-400 to-red-500' : 'bg-cyan-400'}`}
                 style={{ width: `${Math.min((speedRef.current / MAX_SPEED) * 100, 100)}%` }}
               />
            </div>
            <div className="text-xs text-white mt-1 font-bold font-mono shadow-black drop-shadow-md">
               {Math.round(speedRef.current * 10)} KM/H
            </div>
         </div>
      </Html>

      {/* Ship Model Container (For Banking Rotation) */}
      <group ref={modelRef}>

         {/* --- 3D SHIP MESH --- */}

         {/* Main Hull */}
         <mesh rotation={[Math.PI / 2, 0, 0]}>
            <cylinderGeometry args={[0.4, 0.7, 3.5, 8]} />
            <meshStandardMaterial color="#e2e8f0" roughness={0.3} metalness={0.8} />
         </mesh>

         {/* Cockpit Canopy */}
         <mesh position={[0, 0.6, 0.5]} rotation={[0.2, 0, 0]}>
            <boxGeometry args={[0.7, 0.4, 1.4]} />
            <meshStandardMaterial color="#0f172a" roughness={0.1} metalness={0.9} />
         </mesh>

         {/* Glowing Visor */}
         <mesh position={[0, 0.65, 1.0]}>
             <boxGeometry args={[0.6, 0.1, 0.5]} />
             <meshBasicMaterial color="#00ffff" />
         </mesh>

         {/* Wings - Swept Back */}
         <group position={[0, 0, -0.5]}>
            {/* Left Wing */}
            <mesh position={[1.4, 0, -0.5]} rotation={[0, -0.4, -0.1]}>
               <boxGeometry args={[2.5, 0.1, 1.5]} />
               <meshStandardMaterial color="#64748b" roughness={0.5} metalness={0.6} />
            </mesh>
            <mesh position={[2.6, 0, -0.5]}>
               <boxGeometry args={[0.1, 0.4, 1.2]} /> {/* Winglet */}
               <meshStandardMaterial color="#ef4444" emissive="#ef4444" emissiveIntensity={0.5} />
            </mesh>

            {/* Right Wing */}
            <mesh position={[-1.4, 0, -0.5]} rotation={[0, 0.4, 0.1]}>
               <boxGeometry args={[2.5, 0.1, 1.5]} />
               <meshStandardMaterial color="#64748b" roughness={0.5} metalness={0.6} />
            </mesh>
            <mesh position={[-2.6, 0, -0.5]}>
               <boxGeometry args={[0.1, 0.4, 1.2]} /> {/* Winglet */}
               <meshStandardMaterial color="#22c55e" emissive="#22c55e" emissiveIntensity={0.5} />
            </mesh>
         </group>

         {/* Engine System */}
         <group position={[0, 0, -1.8]} ref={engineGlowRef}>
             {/* Nozzle */}
             <mesh rotation={[Math.PI/2, 0, 0]}>
                 <cylinderGeometry args={[0.4, 0.2, 0.6, 16]} />
                 <meshStandardMaterial color="#333" />
             </mesh>

             {/* Plasma Core (Bright White center) */}
             <mesh position={[0, 0, -0.5]} rotation={[Math.PI/2, 0, 0]}>
                 <coneGeometry args={[0.2, 1.0, 16]} />
                 <meshBasicMaterial color="#ffffff" transparent opacity={0.9} blending={AdditiveBlending} depthWrite={false} />
             </mesh>

             {/* Plasma Outer (Blue/Purple gradient) */}
             <mesh position={[0, 0, -0.4]} rotation={[Math.PI/2, 0, 0]}>
                 <coneGeometry args={[0.45, 1.8, 16]} />
                 <meshBasicMaterial color={isBoostActive ? "#ff00aa" : "#00ffff"} transparent opacity={0.6} blending={AdditiveBlending} depthWrite={false} />
             </mesh>
         </group>

         {/* Trail Effect (Always active but variable length) */}
         <group position={[1.8, 0, -0.5]}>
           <Trail width={0.4} length={isBoostActive ? 15 : 6} color={isBoostActive ? "#ff00aa" : "#00ffff"} attenuation={(t) => t * t}>
              <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
           </Trail>
         </group>
         <group position={[-1.8, 0, -0.5]}>
           <Trail width={0.4} length={isBoostActive ? 15 : 6} color={isBoostActive ? "#ff00aa" : "#00ffff"} attenuation={(t) => t * t}>
              <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
           </Trail>
         </group>

      </group>
    </group>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, DoubleSide, Quaternion, MathUtils, Mesh, Color } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// Updated State Machine
type ShipState = 'PLANNING' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });

  // Refs for loop variables to avoid re-renders
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // Movement calculation refs
  const currentSpeedRef = useRef(0);
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const camDistRef = useRef(16); 

  // Leaving State Refs
  const exitVectorRef = useRef(new Vector3());
  const leavingTimeRef = useRef(0);

  // Blinking lights ref
  const lightsRef = useRef<Group>(null);

  // Smooth rotation
  const MAX_SPEED = 28; // Slightly faster for long trips
  const ORBIT_SPEED = 8; // Slower speed for orbiting

  // Helper to generate mission route
  const generateMission = () => {
     // Exclude Sun, Mercury (too hot/close), and ensure we have candidates
     const candidates = PLANETS
        .filter(p => p.id !== 'mercury')
        .map(p => p.id);

     const mission: string[] = [];
     let lastPlanet = 'earth'; // Start logic from earth (conceptually)

     // Pick 5 random planets
     for (let i = 0; i < 5; i++) {
        let next: string;
        let attempts = 0;
        // Find a candidate that is not the same as the last one
        do {
            next = candidates[Math.floor(Math.random() * candidates.length)];
            attempts++;
        } while (next === lastPlanet && attempts < 10);

        mission.push(next);
        lastPlanet = next;
     }

     // Finally, return to Earth
     mission.push('earth');

     return mission;
  };

  // Helper to calculate a safe but close orbit radius for each planet
  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12; // Fallback

     if (p.hasRings) {
         return p.size * 2.5 + 2.0; 
     }
     return p.size * 2.8 + 2.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // --- 0. INITIALIZATION: Spawn at Earth ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        if (startPos.lengthSq() > 1) { // Wait until Earth has valid pos
             startPos.y += 10.0; // Start high
             startPos.x += 10.0; 
             groupRef.current.position.copy(startPos);
             groupRef.current.lookAt(new Vector3(0, 0, 0)); 
             initializedRef.current = true;
             stateRef.current = 'PLANNING';
        }
      }
      return; 
    }

    // Blink Lights Animation
    if (lightsRef.current) {
       const blink = Math.sin(state.clock.elapsedTime * 10) > 0;
       lightsRef.current.visible = blink;
    }

    // --- 1. STATE MACHINE ---

    // PLANNING: Generate the queue once
    if (stateRef.current === 'PLANNING') {
       missionQueueRef.current = generateMission();
       stateRef.current = 'LEAVING'; // Start by "Leaving" spawn point to go to first target
       // Setup initial exit vector away from spawn
       const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
       exitVectorRef.current.copy(forward);
       leavingTimeRef.current = 0;
       return;
    }

    // LEAVING: Fly straight along the tangent (or initial vector)
    // Also acts as the "Transition" state between planets
    if (stateRef.current === 'LEAVING') {
       leavingTimeRef.current += delta;

       // Accelerate to cruise
       currentSpeedRef.current += (MAX_SPEED - currentSpeedRef.current) * 1.5 * delta;

       // Move along exit vector
       const moveVec = exitVectorRef.current.clone().multiplyScalar(currentSpeedRef.current * delta);
       groupRef.current.position.add(moveVec);

       // Banking reset
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
       }

       // After flying away briefly (to clear orbit/spawn), select next target
       if (leavingTimeRef.current > 1.0) {
          // Check if we have a destination
          if (missionQueueRef.current.length > 0) {
             const nextId = missionQueueRef.current.shift()!;
             currentTargetIdRef.current = nextId;

             // Update HUD text
             const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
             setMissionProgress(prev => ({ 
                 current: 6 - missionQueueRef.current.length, // 5 steps + 1 return
                 total: 6,
                 targetName: pName
             }));

             stateRef.current = 'TRAVELING';
          } else {
             stateRef.current = 'COMPLETED';
          }
       }
    }

    // COMPLETED: Mission Done
    if (stateRef.current === 'COMPLETED') {
        // Trigger callback once then stop
        onMissionComplete();
        return;
    }

    // Common Target Position Logic
    let targetObj: Object3D | null = null;
    let targetPos = new Vector3();
    const tId = currentTargetIdRef.current;

    if (tId && planetRefs.current[tId]) {
      targetObj = planetRefs.current[tId];
      targetObj.getWorldPosition(targetPos);
    } else if (stateRef.current === 'TRAVELING') {
        // Target lost or invalid? Skip
        stateRef.current = 'LEAVING';
        return;
    }

    const currentPos = groupRef.current.position.clone();

    // TRAVELING: Fly towards the orbit entry point
    if (stateRef.current === 'TRAVELING' && targetObj) {
      const targetRadius = getSafeOrbitRadius(tId!);

      const dirToPlanet = new Vector3().subVectors(targetPos, currentPos).normalize();

      // Entry point logic: Aim for equator at target radius
      const flatDir = new Vector3(dirToPlanet.x, 0, dirToPlanet.z).normalize();
      const entryPoint = new Vector3(
          targetPos.x - flatDir.x * targetRadius,
          targetPos.y, 
          targetPos.z - flatDir.z * targetRadius
      );

      const distToEntry = currentPos.distanceTo(entryPoint);

      // Decelerate
      let targetSpeed = MAX_SPEED;
      if (distToEntry < 30) targetSpeed = ORBIT_SPEED;

      currentSpeedRef.current += (targetSpeed - currentSpeedRef.current) * 2.0 * delta;

      if (distToEntry < 2) {
         // Arrived
         stateRef.current = 'ORBITING';
         orbitRadiusRef.current = targetRadius;

         const relativePos = new Vector3().subVectors(currentPos, targetPos);
         orbitAngleRef.current = Math.atan2(relativePos.z, relativePos.x);
         totalOrbitTraveledRef.current = 0;
      } else {
         // Move
         const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();
         groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

         // Rotate Ship
         const lookPos = currentPos.clone().add(moveDir);
         const slerpSpeed = distToEntry < 10 ? 3 * delta : 5 * delta;

         const dummyObj = new Object3D();
         dummyObj.position.copy(currentPos);
         dummyObj.lookAt(lookPos);
         groupRef.current.quaternion.slerp(dummyObj.quaternion, slerpSpeed);

         if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
         }
      }
    }

    // ORBITING: Circle the planet
    if (stateRef.current === 'ORBITING' && targetObj) {
       currentSpeedRef.current += (ORBIT_SPEED - currentSpeedRef.current) * 2.0 * delta;

       const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
       const angleDelta = angularSpeed * delta;

       orbitAngleRef.current += angleDelta;
       totalOrbitTraveledRef.current += angleDelta;

       const nextX = targetPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextZ = targetPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextY = targetPos.y; 

       const nextPos = new Vector3(nextX, nextY, nextZ);

       groupRef.current.position.copy(nextPos);

       // Look along tangent
       const futureAngle = orbitAngleRef.current + 0.1;
       const lookX = targetPos.x + Math.cos(futureAngle) * orbitRadiusRef.current;
       const lookZ = targetPos.z + Math.sin(futureAngle) * orbitRadiusRef.current;
       const lookY = targetPos.y; 

       const lookAtPos = new Vector3(lookX, lookY, lookZ);

       const dummyObj = new Object3D();
       dummyObj.position.copy(nextPos);
       dummyObj.lookAt(lookAtPos);
       groupRef.current.quaternion.slerp(dummyObj.quaternion, 8 * delta);

       // Bank
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 4, delta * 3);
       }

       // Exit condition: ~1 full orbit (plus a bit to clear entry point)
       if (totalOrbitTraveledRef.current > Math.PI * 2.2) {
          stateRef.current = 'LEAVING';

          // Determine tangential exit vector
          const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
          exitVectorRef.current.copy(forward);
          leavingTimeRef.current = 0;

          // Note: We don't nullify currentTargetIdRef yet, we do that in LEAVING after some time
          // so the camera doesn't snap away too fast.
       }
    }

    // Update Speed Display
    const displayVal = Math.round(currentSpeedRef.current * 1000);
    if (Math.abs(displayVal - currentSpeedDisplay) > 100) {
        setCurrentSpeedDisplay(displayVal);
    }

    // --- CAMERA LOGIC (Third Person) ---
    const targetCamDist = stateRef.current === 'ORBITING' ? 35 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta * 1.0);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
    const heightOffset = MathUtils.lerp(5, 12, (camDistRef.current - 16) / (35 - 16));

    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    state.camera.position.lerp(desiredCamPos, 0.08);

    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(10));
    state.camera.lookAt(lookTarget);
  });

  const tId = currentTargetIdRef.current;
  const tName = missionProgress.targetName;

  return (
    <>
      {/* REALISTIC STARSHIP MODEL */}
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* Speedometer & Mission HUD */}
        <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-start pointer-events-none select-none gap-2">

                {/* Velocity */}
                <div className="flex flex-col items-start">
