             <ellipse cx="${width * 0.32}" cy="${height * 0.72}" rx="${width * 0.02}" ry="${height * 0.008}" fill="white" opacity="0.9" />
          </g>
          <rect width="100%" height="100%" fill="${midBlue}" opacity="0.1" style="mix-blend-mode: overlay;" />
