        const redSpotOuter = "#D68D64";
        svgContent = `
          <defs>
            <filter id="jupiterGas" x="-20%" y="-20%" width="140%" height="140%">
               <feTurbulence type="fractalNoise" baseFrequency="0.004 0.04" numOctaves="4" seed="42" result="noise"/>
