              const cx = Math.random() * width;
              const cy = Math.random() * height;
              const r = Math.random() * 4 + 1;
              return `
                <circle cx="${cx}" cy="${cy}" r="${r}" fill="#FFFFFF" opacity="0.9" />
                <circle cx="${cx}" cy="${cy}" r="${r * 4}" fill="#FFFFFF" opacity="0.15" />
