      stationRef.current.rotation.y += delta * 0.8 * simulationSpeed;
    }

    // 太阳翼缓慢调整角度（模拟对日定向）
    if (solarPanelRef.current && !isPaused) {
       // Gentle oscillation
       solarPanelRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.5) * 0.1;
    }
