            document.body.style.cursor = 'auto';
            setHovered(false);
          }}
        > 

           {/* --- Q版天宫空间站 (T字构型) --- */}
           {/* Rotation aligns Core along Z axis. Orbit motion is along Local X (Parent -Z tangent) */}
