const Moon: React.FC<{ isPaused: boolean; simulationSpeed: number; showOrbit: boolean; onSelect: (id: string) => void }> = ({ isPaused, simulationSpeed, showOrbit, onSelect }) => {
  const moonRef = useRef<Group>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  // Create static data for Moon texture generation
  const textureUrl = useMemo(() => generatePlanetTexture(MOON_DATA), []);
  const texture = useMemo(() => new TextureLoader().load(textureUrl), [textureUrl]);

  useFrame((state, delta) => {
    if (moonRef.current && !isPaused) {
      // Moon orbits Earth (Reduced speed from 0.4 to 0.2)
      moonRef.current.rotation.y += delta * 0.2 * simulationSpeed;
    }
  });

  return (
    <group rotation={[0, 0, Math.PI / 8]}> {/* Slight inclination of moon orbit */}
      <group ref={moonRef}>
        {/* Moon Object */}
        <mesh 
          position={[3.5, 0, 0]}
          onPointerDown={(e) => {
            e.stopPropagation();
            clickStartRef.current = { x: e.clientX, y: e.clientY };
          }}
          onClick={(e) => {
            e.stopPropagation();
            const dx = e.clientX - clickStartRef.current.x;
            const dy = e.clientY - clickStartRef.current.y;
            const distance = Math.sqrt(dx * dx + dy * dy);
            if (distance < 5) {
              onSelect('moon');
            }
          }}
          onPointerOver={() => {
            document.body.style.cursor = 'pointer';
            setHovered(true);
          }}
          onPointerOut={() => {
            document.body.style.cursor = 'auto';
            setHovered(false);
          }}
        >
          <sphereGeometry args={[0.45, 32, 32]} />
          <meshPhysicalMaterial 
            map={texture}
            color="#ffffff" 
            roughness={0.8}
            metalness={0.1}
            // Inner Glow: Use texture as emissive map
            emissiveMap={texture}
            emissive="#ffffff"
            // Reduced Intensity 0.3
            emissiveIntensity={hovered ? 0.3 : 0}
          />
          {/* Tech Hover Label */}
          {hovered && (
            <TechLabel name={MOON_DATA.name} offset={0.45} />
          )}
        </mesh>

        {/* Moon Orbit Path Visual */}
        <mesh rotation={[Math.PI / 2, 0, 0]} visible={showOrbit}>
           <ringGeometry args={[3.45, 3.55, 64]} />
           <meshBasicMaterial color="#ffffff" opacity={0.15} transparent side={DoubleSide} />
        </mesh>
      </group>
    </group>
  );
};

// Generic Satellite Component (Used for Jupiter's & Saturn's Moons)
const Satellite: React.FC<{ 
  data: PlanetData;
  isPaused: boolean; 
  simulationSpeed: number;
  onSelect: (id: string) => void;
  isSelected: boolean;
  showOrbit: boolean;
}> = ({ data, isPaused, simulationSpeed, onSelect, isSelected, showOrbit }) => {
  const ref = useRef<Group>(null);
  const inclinationGroupRef = useRef<Group>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  const textureUrl = useMemo(() => generatePlanetTexture(data), [data]);
  const texture = useMemo(() => new TextureLoader().load(textureUrl), [textureUrl]);

  // Generate Atmosphere Glow (For Titan)
  const glowTextureUrl = useMemo(() => data.atmosphereColor ? generateGenericGlowTexture() : null, [data.atmosphereColor]);
  const glowTexture = useMemo(() => glowTextureUrl ? new TextureLoader().load(glowTextureUrl) : null, [glowTextureUrl]);

  useFrame((state, delta) => {
    if (ref.current && !isPaused) {
      ref.current.rotation.y += delta * data.speed * simulationSpeed;
    }
  });

  return (
    <group ref={inclinationGroupRef} rotation={[0, 0, data.orbitInclination || 0]}>
      <group ref={ref}>
        {/* Satellite Object */}
        <mesh 
          position={[data.distance, 0, 0]}
          onPointerDown={(e) => {
            e.stopPropagation();
            clickStartRef.current = { x: e.clientX, y: e.clientY };
          }}
          onClick={(e) => {
            e.stopPropagation();
            // Calculate distance moved
            const dx = e.clientX - clickStartRef.current.x;
            const dy = e.clientY - clickStartRef.current.y;
            const distance = Math.sqrt(dx * dx + dy * dy);

            // Only trigger select if moved less than 5 pixels (click, not drag)
            if (distance < 5) {
              onSelect(data.id);
            }
          }}
          onPointerOver={() => {
            document.body.style.cursor = 'pointer';
            setHovered(true);
          }}
          onPointerOut={() => {
            document.body.style.cursor = 'auto';
            setHovered(false);
          }}
        >
          <sphereGeometry args={[data.size, 32, 32]} />
          <meshPhysicalMaterial 
            map={texture}
            color="#ffffff" 
            roughness={0.7}
            metalness={0.1}
            // Inner Glow Logic
            emissiveMap={texture}
            emissive="#ffffff"
            // Reduced Intensity 0.3
            emissiveIntensity={isSelected || hovered ? 0.3 : 0}
          />
          {/* Tech Hover Label */}
          {hovered && (
            <TechLabel name={data.name} offset={data.size} />
          )}

          {/* Atmosphere Glow for Titan */}
          {data.atmosphereColor && glowTexture && (
            <Billboard>
              <mesh scale={[data.size * 2.8, data.size * 2.8, 1]}>
                <planeGeometry args={[1, 1]} />
                <meshBasicMaterial 
                  map={glowTexture} 
                  transparent 
                  opacity={0.3} 
                  depthWrite={false}
                  blending={AdditiveBlending}
                  color={new Color(data.atmosphereColor)}
                />
              </mesh>
            </Billboard>
          )}

        </mesh>

        {/* Orbit Path Visual */}
        <mesh rotation={[Math.PI / 2, 0, 0]} visible={showOrbit}>
           <ringGeometry args={[data.distance - 0.03, data.distance + 0.03, 64]} />
           <meshBasicMaterial color="#ffffff" opacity={0.1} transparent side={DoubleSide} />
        </mesh>
      </group>
    </group>
  );
};

