export const Planet: React.FC<PlanetProps> = ({ 
  data, 
  isSelected, 
  onSelect, 
  isPaused, 
  simulationSpeed,
  earthPositionRef,
  planetRefs,
  isStarshipActive,
  showOrbit
}) => {
  const meshRef = useRef<Mesh>(null);
  const orbitGroupRef = useRef<Group>(null);
  const inclinationGroupRef = useRef<Group>(null); // New group for orbital inclination
  const [hovered, setHovered] = useState(false);

  // Track click start position to differentiate click from drag
  const clickStartRef = useRef({ x: 0, y: 0 });

  // Register this planet to the refs map for the Starship
  useEffect(() => {
    // We register the planet's internal orbit position group (orbitGroupRef)
    // so the starship flies to where the planet IS.
    if (orbitGroupRef.current) {
      planetRefs.current[data.id] = orbitGroupRef.current;
    }
  }, [data.id, planetRefs]);

  // Use a Ref to track orbit angle so we can pause/resume smoothly
  const orbitAngleRef = useRef(Math.random() * Math.PI * 2);

  // Generate SVG Texture for Surface
  const textureUrl = useMemo(() => generatePlanetTexture(data), [data]);
  const texture = useMemo(() => new TextureLoader().load(textureUrl), [textureUrl]);

  // Generate SVG Texture for Rings (if applicable)
  const ringTextureUrl = useMemo(() => {
    return data.hasRings && data.ringColor ? generateRingTexture(data.id, data.ringColor) : null;
  }, [data]);
  const ringTexture = useMemo(() => ringTextureUrl ? new TextureLoader().load(ringTextureUrl) : null, [ringTextureUrl]);

  // Generate Generic Soft Glow Texture for Atmosphere
  const glowTextureUrl = useMemo(() => data.atmosphereColor ? generateGenericGlowTexture() : null, [data.atmosphereColor]);
  const glowTexture = useMemo(() => glowTextureUrl ? new TextureLoader().load(glowTextureUrl) : null, [glowTextureUrl]);

  useFrame((state, delta) => {
    if (!orbitGroupRef.current || !meshRef.current) return;

    if (!isPaused) {
      // Orbit logic - Update Accumulator
      // Reduced base speed multiplier from 0.2 to 0.1 for slower 1x simulation
      orbitAngleRef.current += delta * data.speed * 0.1 * simulationSpeed;

      // Counter-Clockwise Revolution:
      // x = cos(angle), z = -sin(angle)
      const x = Math.cos(orbitAngleRef.current) * data.distance;
      const z = -Math.sin(orbitAngleRef.current) * data.distance;

      // The orbitGroupRef moves in a flat circle relative to its parent (the Inclination Group)
      orbitGroupRef.current.position.set(x, 0, z);

      // Self rotation logic
      meshRef.current.rotation.y += data.rotationSpeed * simulationSpeed;

      // Update Earth's position ref if this is Earth
      // NOTE: We need the WORLD position since we are now nesting groups
      if (data.id === 'earth') {
        // Using getWorldPosition because of the nested groups (inclination > orbit > planet)
        orbitGroupRef.current.getWorldPosition(earthPositionRef.current);
      }
    }
  });

  return (
    // Outer Group: Applies Orbital Inclination (The tilt of the entire orbit path)
    // We rotate around the Z axis to tilt the plane left/right relative to the sun
    <group ref={inclinationGroupRef} rotation={[0, 0, data.orbitInclination || 0]}>

      {/* Orbit Path Visual (Ring) - Stays static within the inclined plane */}
      {/* HIDE when Starship is active for cleaner look */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} visible={!isStarshipActive && showOrbit}>
        <ringGeometry args={[data.distance - 0.05, data.distance + 0.05, 128]} />
        <meshBasicMaterial color="#ffffff" opacity={0.35} transparent side={DoubleSide} />
      </mesh>

      {/* The Planet Group - Moves along the orbit path */}
      <group ref={orbitGroupRef}>

        {/* Axial Tilt Group - Apply planet's specific self-tilt here */}
        <group rotation={[0, 0, data.axisTilt || 0]}>

          {/* Main Planet Sphere - Rotation (Day/Night) happens here */}
          <mesh
            ref={meshRef}
            onPointerDown={(e) => {
              e.stopPropagation();
              clickStartRef.current = { x: e.clientX, y: e.clientY };
            }}
            onClick={(e) => {
              e.stopPropagation();
              // Calculate distance moved
              const dx = e.clientX - clickStartRef.current.x;
              const dy = e.clientY - clickStartRef.current.y;
              const distance = Math.sqrt(dx * dx + dy * dy);

              // Only trigger select if moved less than 5 pixels (click, not drag)
              if (distance < 5) {
                onSelect(data.id);
              }
            }}
            onPointerOver={() => {
              document.body.style.cursor = 'pointer';
              setHovered(true);
            }}
            onPointerOut={() => {
              document.body.style.cursor = 'auto';
              setHovered(false);
            }}
          >
            <sphereGeometry args={[data.size, 64, 64]} />
            <meshPhysicalMaterial 
              map={texture}
              color="#ffffff" 
              roughness={0.6}
              metalness={0.2}
              clearcoat={0.3}
              clearcoatRoughness={0.4}
              // Inner Glow Logic: Use map as emissive map
              emissiveMap={texture}
              emissive="#ffffff"
              // Adjusted brightness to 0.2
              emissiveIntensity={isSelected || hovered ? 0.2 : 0}
            />

            {/* Tech Hover Label */}
            {hovered && (
               <TechLabel name={data.name} offset={data.size} />
            )}
          </mesh>

          {/* Rings - Tilted with the planet */}
          {data.hasRings && ringTexture && (
            // Rotate X by -90 to lay flat relative to the tilted group
            <mesh rotation={[-Math.PI / 2, 0, 0]}>
              <ringGeometry args={[data.size * 1.4, data.size * 2.3, 128]} />
              <meshStandardMaterial 
                map={ringTexture}
                color="#ffffff" 
                opacity={0.9} 
                transparent 
                side={DoubleSide} 
                roughness={0.4}
                metalness={0.2}
                // Add slight warm glow to prevent dead black on unlit side, simulating scattered light
                emissive={data.id === 'saturn' ? "#443322" : "#000000"} 
                emissiveIntensity={0.2}
              />
            </mesh>
          )}
        </group>

        {/* --- EARTH SPECIFIC SATELLITES --- */}
        {data.id === 'earth' && (
          <>
            {/* Moon: Placed outside the axial tilt group so it orbits the center of Earth's position */}
            <Moon 
              isPaused={isPaused} 
              simulationSpeed={simulationSpeed} 
              showOrbit={showOrbit} 
              onSelect={onSelect}
            />

            {/* Tiangong Space Station: Lower orbit than Moon */}
            <TiangongStation 
              isPaused={isPaused} 
              simulationSpeed={simulationSpeed} 
              showOrbit={showOrbit} 
              onSelect={onSelect}
            />
          </>
        )}

        {/* --- JUPITER SPECIFIC SATELLITES (GALILEAN MOONS) --- */}
        {data.id === 'jupiter' && (
           <JupiterMoons 
             isPaused={isPaused} 
             simulationSpeed={simulationSpeed}
             onSelect={onSelect}
             selectedId={isSelected ? data.id : null} // Simple pass-through check, handled better in App state
             showOrbit={showOrbit}
           />
        )}

        {/* --- SATURN SPECIFIC SATELLITES --- */}
        {data.id === 'saturn' && (
           <SaturnMoons 
             isPaused={isPaused} 
             simulationSpeed={simulationSpeed}
             onSelect={onSelect}
             selectedId={isSelected ? data.id : null} 
             showOrbit={showOrbit}
           />
        )}

        {/* Atmosphere Glow Shell (Billboard) - Replaced Shader with Sprite/Billboard method */}
        {/* We place it OUTSIDE the tilted group so it stays upright facing the camera properly, but follows position */}
        {data.atmosphereColor && glowTexture && (
           <Billboard>
              {/* Scale it up ~2.8x the planet size for a soft diffuse glow */}
              <mesh scale={[data.size * 2.8, data.size * 2.8, 1]}>
                <planeGeometry args={[1, 1]} />
                <meshBasicMaterial 
                  map={glowTexture} 
                  transparent 
                  opacity={0.25} // Low opacity for subtle effect
                  depthWrite={false}
                  blending={AdditiveBlending}
                  color={new Color(data.atmosphereColor)}
                />
              </mesh>
           </Billboard>
        )}

      </group>
    </group>
  );
};

import React, { useRef, useState, useMemo } from 'react';
import { useFrame, extend, ReactThreeFiber } from '@react-three/fiber';
import { Mesh, Color, Vector3, ShaderMaterial, AdditiveBlending, BackSide } from 'three';
import { Html, Billboard, shaderMaterial } from '@react-three/drei';
import { SUN_DATA } from '../constants';

// --- SHADER DEFINITIONS ---

// 1. Sun Surface Shader (Photosphere)
// Simulates granulation, convection cells, and limb darkening
const SunSurfaceMaterial = shaderMaterial(
  {
    uTime: 0,
    uColorCore: new Color('#FFFFA0'),      // Very bright yellow/white center
    uColorPrimary: new Color('#FDB813'),   // Main Gold
    uColorSecondary: new Color('#F57C00'), // Deep Orange/Red
    uColorDark: new Color('#5D4037'),      // Dark spots/Lanes
  },
  // Vertex Shader
  `
    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vLayer0;
    varying vec3 vLayer1;
    varying vec3 vLayer2;

    uniform float uTime;

    void main() {
      vUv = uv;
      vNormal = normalize(normalMatrix * normal);
      vPosition = position; // Local position

      // Generate 3 shifting coordinate layers for noise
      float t = uTime * 0.05;
      vLayer0 = position + vec3(t, t, 0.0);
      vLayer1 = position * 1.5 + vec3(t * 1.2, -t, 0.0);
      vLayer2 = position * 2.0 + vec3(-t, t * 1.5, 0.0);

      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  // Fragment Shader
  `
    uniform float uTime;
    uniform vec3 uColorCore;
    uniform vec3 uColorPrimary;
    uniform vec3 uColorSecondary;
    uniform vec3 uColorDark;

    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vLayer0;
    varying vec3 vLayer1;
    varying vec3 vLayer2;

    // Simplex Noise Helper
    vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
    vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

    float snoise(vec3 v) {
      const vec2 C = vec2(1.0/6.0, 1.0/3.0);
      const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);

      // First corner
      vec3 i  = floor(v + dot(v, C.yyy));
      vec3 x0 = v - i + dot(i, C.xxx);

      // Other corners
      vec3 g = step(x0.yzx, x0.xyz);
      vec3 l = 1.0 - g;
      vec3 i1 = min( g.xyz, l.zxy );
      vec3 i2 = max( g.xyz, l.zxy );

      vec3 x1 = x0 - i1 + C.xxx;
      vec3 x2 = x0 - i2 + C.yyy;
      vec3 x3 = x0 - D.yyy;

      // Permutations
      i = mod289(i); 
      vec4 p = permute( permute( permute( 
                 i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
               + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
               + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

      float n_ = 0.142857142857; // 1.0/7.0
      vec3  ns = n_ * D.wyz - D.xzx;

      vec4 j = p - 49.0 * floor(p * ns.z * ns.z);

      vec4 x_ = floor(j * ns.z);
      vec4 y_ = floor(j - 7.0 * x_ );

      vec4 x = x_ *ns.x + ns.yyyy;
      vec4 y = y_ *ns.x + ns.yyyy;
      vec4 h = 1.0 - abs(x) - abs(y);

      vec4 b0 = vec4( x.xy, y.xy );
      vec4 b1 = vec4( x.zw, y.zw );

      vec4 s0 = floor(b0)*2.0 + 1.0;
      vec4 s1 = floor(b1)*2.0 + 1.0;
      vec4 sh = -step(h, vec4(0.0));

      vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
      vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

      vec3 p0 = vec3(a0.xy,h.x);
      vec3 p1 = vec3(a0.zw,h.y);
      vec3 p2 = vec3(a1.xy,h.z);
      vec3 p3 = vec3(a1.zw,h.w);

      vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
      p0 *= norm.x;
      p1 *= norm.y;
      p2 *= norm.z;
      p3 *= norm.w;

      vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
      m = m * m;
      return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                    dot(p2,x2), dot(p3,x3) ) );
    }

    void main() {
      // FBM Noise (3 Octaves)
      float n = 0.0;
      n += 0.50 * snoise(vLayer0);
      n += 0.25 * snoise(vLayer1);
      n += 0.15 * snoise(vLayer2);

      // Normalize noise roughly to 0.0 - 1.0
      float brightness = smoothstep(-0.4, 0.6, n);

      // Color mixing based on noise heat
      vec3 col = mix(uColorDark, uColorSecondary, brightness);
      col = mix(col, uColorPrimary, smoothstep(0.2, 0.8, brightness));
      col = mix(col, uColorCore, smoothstep(0.7, 1.0, brightness));

      // Limb Darkening (Fresnel Effect)
      // Standard view-space normal.z is approx dot(view, normal) for sphere
      float fresnel = vNormal.z; 

      // Enhance limb darkening: Edges become redder/darker
      float limb = smoothstep(0.0, 0.7, fresnel);
      col *= (0.3 + 0.7 * limb); // Darken edges

      // Edge glow rim
      float rim = 1.0 - fresnel;
      vec3 rimColor = vec3(1.0, 0.3, 0.0) * pow(rim, 3.0) * 0.5;
      col += rimColor;

      gl_FragColor = vec4(col, 1.0);

      // Tone mapping fix (simple reinhard-ish)
      // gl_FragColor.rgb = gl_FragColor.rgb / (gl_FragColor.rgb + vec3(1.0));
    }
  `
);

// 2. Sun Corona Shader (Atmosphere)
// Simulates pulsating plasma rays
const SunCoronaMaterial = shaderMaterial(
  {
    uTime: 0,
    uColorInner: new Color('#FFD700'),
    uColorOuter: new Color('#FF4500'),
  },
  // Vertex
  `
    varying vec2 vUv;
    varying vec3 vPosition;
    void main() {
      vUv = uv;
      vPosition = position;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  // Fragment
  `
    uniform float uTime;
    uniform vec3 uColorInner;
    uniform vec3 uColorOuter;
    varying vec2 vUv;
    varying vec3 vPosition;

    // Simple noise for rays
    float random(vec2 st) {
        return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
    }

    void main() {
      // Distance from center (0.5, 0.5)
      vec2 center = vec2(0.5);
      float dist = length(vUv - center) * 2.0; // 0 at center, 1 at edge

      // Circular masking
      if (dist > 1.0) discard;

      // Angle for rays
      vec2 dir = vUv - center;
      float angle = atan(dir.y, dir.x);

      // Dynamic Rays
      float t = uTime * 0.2;
      float noise = sin(angle * 20.0 + t) * 0.1 
                  + sin(angle * 13.0 - t * 1.5) * 0.05 
                  + sin(angle * 5.0 + t * 0.5) * 0.2;

      // Radial falloff + noise
      // Create a "Hollow" center so the main sun is visible
      float alpha = 1.0 - smoothstep(0.2 + noise * 0.1, 0.8, dist);

      // Inner fade (Soft edge next to sun surface)
      alpha *= smoothstep(0.3, 0.4, dist); 

      // Pulsating intensity
      float pulse = 0.8 + 0.2 * sin(uTime * 1.0);
      alpha *= pulse;

      vec3 col = mix(uColorInner, uColorOuter, dist);

      gl_FragColor = vec4(col, alpha * 0.6); // Base opacity
    }
  `
);

extend({ SunSurfaceMaterial, SunCoronaMaterial });

// Add types for custom materials
declare global {
  namespace JSX {
    interface IntrinsicElements {
      sunSurfaceMaterial: ReactThreeFiber.Object3DNode<ShaderMaterial, typeof SunSurfaceMaterial>;
      sunCoronaMaterial: ReactThreeFiber.Object3DNode<ShaderMaterial, typeof SunCoronaMaterial>;
    }
  }
}

interface SunProps {
  onSelect: (id: string) => void;
  isSelected: boolean;
  isPaused: boolean;
  simulationSpeed: number;
}

export const Sun: React.FC<SunProps> = ({ onSelect, isSelected, isPaused, simulationSpeed }) => {
  const meshRef = useRef<Mesh>(null);
  const surfaceMatRef = useRef<ShaderMaterial>(null);
  const coronaMatRef = useRef<ShaderMaterial>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  useFrame((state, delta) => {
    // Animate Shaders
    const time = state.clock.elapsedTime;

    if (surfaceMatRef.current) {
       surfaceMatRef.current.uniforms.uTime.value = time;
    }
    if (coronaMatRef.current) {
       coronaMatRef.current.uniforms.uTime.value = time;
    }

    if (meshRef.current && !isPaused) {
      // Very slow rotation for the mesh itself (the texture is animated by shader mostly)
      meshRef.current.rotation.y += delta * 0.002 * simulationSpeed;
    }
  });

  return (
    <group>
      {/* 1. Main Sun Body - High Quality Shader */}
      <mesh 
        ref={meshRef}
        onPointerDown={(e) => {
          e.stopPropagation();
          clickStartRef.current = { x: e.clientX, y: e.clientY };
        }}
        onClick={(e) => {
          e.stopPropagation();
          const dx = e.clientX - clickStartRef.current.x;
          const dy = e.clientY - clickStartRef.current.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          if (distance < 5) {
            onSelect(SUN_DATA.id);
          }
        }}
        onPointerOver={() => {
          document.body.style.cursor = 'pointer';
          setHovered(true);
        }}
        onPointerOut={() => {
          document.body.style.cursor = 'auto';
          setHovered(false);
        }}
      >
        <sphereGeometry args={[SUN_DATA.size, 128, 128]} /> {/* Increased segments for smooth limb darkening */}

        {/* @ts-ignore */}
        <sunSurfaceMaterial 
          ref={surfaceMatRef} 
          transparent={false}
        />

        {/* Tech Style Hover Label */}
        {hovered && (
          <Html position={[0, SUN_DATA.size, 0]} zIndexRange={[100, 0]} style={{ pointerEvents: 'none' }}>
            <div className="absolute left-1/2 -translate-x-1/2 bottom-0 pb-1 flex flex-col items-center w-40">

              {/* Label Box */}
              <div className="bg-orange-900/80 backdrop-blur-md border border-orange-500/30 px-3 py-1.5 rounded-sm shadow-[0_0_15px_rgba(251,146,60,0.3)] relative animate-fade-in-up transition-all duration-300">

                {/* Tech Corners (Orange for Sun) */}
                <div className="absolute -top-px -left-px w-1.5 h-1.5 border-l-2 border-t-2 border-orange-400"></div>
                <div className="absolute -top-px -right-px w-1.5 h-1.5 border-r-2 border-t-2 border-orange-400"></div>
                <div className="absolute -bottom-px -left-px w-1.5 h-1.5 border-l-2 border-b-2 border-orange-400"></div>
                <div className="absolute -bottom-px -right-px w-1.5 h-1.5 border-r-2 border-b-2 border-orange-400"></div>

                {/* Scanline / Glow Overlay */}
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-orange-400/10 to-transparent opacity-50"></div>

                <div className="flex flex-col items-center relative z-10">
                  <span className="text-orange-50 text-xs font-bold whitespace-nowrap tracking-wider flex items-center gap-1.5" style={{ textShadow: '0 0 10px rgba(251,146,60,0.6)' }}>
                    <span className="w-1 h-1 bg-orange-400 rounded-full animate-pulse shadow-[0_0_5px_#fb923c]"></span>
                    {SUN_DATA.name}
                  </span>
                </div>
              </div>

              {/* Connector Line (Length makes it float high) */}
              <div className="w-px h-12 bg-gradient-to-b from-orange-500/60 to-transparent mt-[-1px]"></div>

              {/* Anchor Dot */}
              <div className="w-1 h-1 bg-orange-500/50 rounded-full"></div>
            </div>
          </Html>
        )}
      </mesh>

      {/* 2. Dynamic Corona / Atmosphere (Outer Glow) */}
      <Billboard>
         <mesh position={[0, 0, 0]}>
            <planeGeometry args={[SUN_DATA.size * 3.5, SUN_DATA.size * 3.5]} />
            {/* @ts-ignore */}
            <sunCoronaMaterial 
               ref={coronaMatRef} 
               transparent 
               depthWrite={false} 
               blending={AdditiveBlending}
            />
         </mesh>
      </Billboard>

    </group>
  );
};

