import React, { useRef, useState, useMemo } from 'react';
import { useFrame, extend, ReactThreeFiber } from '@react-three/fiber';
import { Mesh, Color, Vector3, ShaderMaterial, AdditiveBlending, BackSide } from 'three';
import { Html, Billboard, shaderMaterial } from '@react-three/drei';
import { SUN_DATA } from '../constants';

// --- SHADER DEFINITIONS ---

// 1. Sun Surface Shader (Photosphere)
// Simulates granulation (rice grains), distinct sunspots, and realistic limb darkening
const SunSurfaceMaterial = shaderMaterial(
  {
    uTime: 0,
    uColorCore: new Color('#FFF5E6'),      // Bright warm center (Light/White Gold)
    uColorPrimary: new Color('#FFC107'),   // Main Surface (Golden Yellow)
    uColorSecondary: new Color('#FF9800'), // Secondary (Orange)
    uColorSpot: new Color('#5D4037'),      // Sunspots (Dark Brown, not pure black)
  },
  // Vertex Shader
  `
    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vNoiseCoord;

    uniform float uTime;

    void main() {
      vUv = uv;
      vNormal = normalize(normalMatrix * normal);
      vPosition = position; 

      // Slowly rotating noise coordinate
      vNoiseCoord = position + vec3(uTime * 0.05, uTime * 0.02, 0.0);

      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  // Fragment Shader
  `
    uniform float uTime;
    uniform vec3 uColorCore;
    uniform vec3 uColorPrimary;
    uniform vec3 uColorSecondary;
    uniform vec3 uColorSpot;

    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vNoiseCoord;

    // Simplex Noise Helper
    vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
    vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

    float snoise(vec3 v) {
      const vec2 C = vec2(1.0/6.0, 1.0/3.0);
      const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);

      vec3 i  = floor(v + dot(v, C.yyy));
      vec3 x0 = v - i + dot(i, C.xxx);

      vec3 g = step(x0.yzx, x0.xyz);
      vec3 l = 1.0 - g;
      vec3 i1 = min( g.xyz, l.zxy );
      vec3 i2 = max( g.xyz, l.zxy );

      vec3 x1 = x0 - i1 + C.xxx;
      vec3 x2 = x0 - i2 + C.yyy;
      vec3 x3 = x0 - D.yyy;

      i = mod289(i); 
      vec4 p = permute( permute( permute( 
                 i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
               + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
               + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

      float n_ = 0.142857142857; 
      vec3  ns = n_ * D.wyz - D.xzx;

      vec4 j = p - 49.0 * floor(p * ns.z * ns.z);

      vec4 x_ = floor(j * ns.z);
      vec4 y_ = floor(j - 7.0 * x_ );

      vec4 x = x_ *ns.x + ns.yyyy;
      vec4 y = y_ *ns.x + ns.yyyy;
      vec4 h = 1.0 - abs(x) - abs(y);

      vec4 b0 = vec4( x.xy, y.xy );
      vec4 b1 = vec4( x.zw, y.zw );

      vec4 s0 = floor(b0)*2.0 + 1.0;
      vec4 s1 = floor(b1)*2.0 + 1.0;
      vec4 sh = -step(h, vec4(0.0));

      vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
      vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

      vec3 p0 = vec3(a0.xy,h.x);
      vec3 p1 = vec3(a0.zw,h.y);
      vec3 p2 = vec3(a1.xy,h.z);
      vec3 p3 = vec3(a1.zw,h.w);

      vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
      p0 *= norm.x;
      p1 *= norm.y;
      p2 *= norm.z;
      p3 *= norm.w;

      vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
      m = m * m;
      return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                    dot(p2,x2), dot(p3,x3) ) );
    }

    void main() {
      // 1. Surface Granulation (Fine texture)
      float grain = snoise(vNoiseCoord * 15.0);

      // 2. Macro Structure (For sunspots)
      // Use lower frequency noise to determine WHERE spots can appear
      float macro = snoise(vNoiseCoord * 1.5 + vec3(10.0)); 

      // 3. Base Color Mixing
      // Mix Primary (Gold) and Secondary (Orange) based on grain
      vec3 color = mix(uColorPrimary, uColorSecondary, grain * 0.15 + 0.15);

      // 4. Sunspots
      // Threshold the macro noise to create isolated dark patches
      // The threshold 0.6 means only the 'peaks' of the noise become spots
      float spotThreshold = 0.6;
      float spotIntensity = smoothstep(spotThreshold, spotThreshold + 0.15, macro);

      // Add irregularity to spots using grain
      spotIntensity *= smoothstep(0.2, 0.8, grain + 0.5);

      // Apply spot color (Dark Brown)
      color = mix(color, uColorSpot, spotIntensity);

      // 5. Faculae (Bright regions around spots)
      // Just outside the spots, make it brighter
      float faculae = smoothstep(spotThreshold - 0.2, spotThreshold, macro) * (1.0 - spotIntensity);
      color = mix(color, uColorCore, faculae * 0.4);

      // 6. Limb Darkening (Physics)
      // Darkens the edges to simulate looking through thicker atmosphere
      float viewDot = dot(vNormal, vec3(0.0, 0.0, 1.0)); // View space normal z is cosine of angle
      float limb = 1.0 - viewDot;

      // Deepen the edge color towards orange/reddish brown
      vec3 limbColor = vec3(0.8, 0.3, 0.0);
      color = mix(color, limbColor, pow(limb, 2.5) * 0.7);

      gl_FragColor = vec4(color, 1.0);
    }
  `
);

// 2. Sun Corona Shader (Atmosphere)
// Soft, golden glow, less "spiky" and more "hazy"
const SunCoronaMaterial = shaderMaterial(
  {
    uTime: 0,
    uColorInner: new Color('#FFD54F'), // Light Amber
    uColorOuter: new Color('#FF6F00'), // Dark Amber
  },
  // Vertex
  `
    varying vec2 vUv;
    void main() {
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  // Fragment
  `
    uniform float uTime;
    uniform vec3 uColorInner;
    uniform vec3 uColorOuter;
    varying vec2 vUv;

    void main() {
      vec2 center = vec2(0.5);
      float dist = length(vUv - center) * 2.0; 

      if (dist > 1.0) discard;

      // Soft pulsing
      float pulse = 0.05 * sin(uTime * 1.5);

      // Radial gradient with exponential falloff for "glow" look
      float alpha = 1.0 - dist;
      alpha = pow(alpha, 1.8 + pulse); // Sharper falloff

      // Mask inner part to not cover the sun completely
      // Smoothly fade in starting from the sun's edge (approx 0.3 radius in UV space)
      float innerFade = smoothstep(0.0, 0.2, dist); 

      vec3 col = mix(uColorInner, uColorOuter, dist);

      // Final Alpha
      float finalAlpha = alpha * 0.5 * innerFade;

      gl_FragColor = vec4(col, finalAlpha);
    }
  `
);

extend({ SunSurfaceMaterial, SunCoronaMaterial });

