      vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
      p0 *= norm.x;
      p1 *= norm.y;
      p2 *= norm.z;
      p3 *= norm.w;

      vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
      m = m * m;
      return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                    dot(p2,x2), dot(p3,x3) ) );
    }

    void main() {
      // 1. Surface Granulation (Fine texture)
      float grain = snoise(vNoiseCoord * 15.0);

      // 2. Macro Structure (For sunspots)
      // Use lower frequency noise to determine WHERE spots can appear
      float macro = snoise(vNoiseCoord * 1.5 + vec3(10.0)); 

      // 3. Base Color Mixing
      // Mix Primary (Gold) and Secondary (Orange) based on grain
      vec3 color = mix(uColorPrimary, uColorSecondary, grain * 0.15 + 0.15);

      // 4. Sunspots
      // Threshold the macro noise to create isolated dark patches
      // The threshold 0.6 means only the 'peaks' of the noise become spots
      float spotThreshold = 0.6;
      float spotIntensity = smoothstep(spotThreshold, spotThreshold + 0.15, macro);

      // Add irregularity to spots using grain
      spotIntensity *= smoothstep(0.2, 0.8, grain + 0.5);

      // Apply spot color (Dark Brown)
      color = mix(color, uColorSpot, spotIntensity);

      // 5. Faculae (Bright regions around spots)
      // Just outside the spots, make it brighter
      float faculae = smoothstep(spotThreshold - 0.2, spotThreshold, macro) * (1.0 - spotIntensity);
      color = mix(color, uColorCore, faculae * 0.4);

      // 6. Limb Darkening (Physics)
      // Darkens the edges to simulate looking through thicker atmosphere
      float viewDot = dot(vNormal, vec3(0.0, 0.0, 1.0)); // View space normal z is cosine of angle
      float limb = 1.0 - viewDot;

      // Deepen the edge color towards orange/reddish brown
      vec3 limbColor = vec3(0.8, 0.3, 0.0);
      color = mix(color, limbColor, pow(limb, 2.5) * 0.7);

      gl_FragColor = vec4(color, 1.0);
    }
  `
);

