// Soft, golden glow, less "spiky" and more "hazy"
const SunCoronaMaterial = shaderMaterial(
  {
    uTime: 0,
    uColorInner: new Color('#FFD54F'), // Light Amber
    uColorOuter: new Color('#FF6F00'), // Dark Amber
  },
