      const vec2 C = vec2(1.0/6.0, 1.0/3.0);
      const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);

      vec3 i  = floor(v + dot(v, C.yyy));
      vec3 x0 = v - i + dot(i, C.xxx);

      vec3 g = step(x0.yzx, x0.xyz);
      vec3 l = 1.0 - g;
      vec3 i1 = min( g.xyz, l.zxy );
      vec3 i2 = max( g.xyz, l.zxy );

      vec3 x1 = x0 - i1 + C.xxx;
      vec3 x2 = x0 - i2 + C.yyy;
      vec3 x3 = x0 - D.yyy;

      i = mod289(i); 
      vec4 p = permute( permute( permute( 
                 i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
               + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
               + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

      float n_ = 0.142857142857; 
      vec3  ns = n_ * D.wyz - D.xzx;

      vec4 j = p - 49.0 * floor(p * ns.z * ns.z);

      vec4 x_ = floor(j * ns.z);
      vec4 y_ = floor(j - 7.0 * x_ );

      vec4 x = x_ *ns.x + ns.yyyy;
      vec4 y = y_ *ns.x + ns.yyyy;
      vec4 h = 1.0 - abs(x) - abs(y);

      vec4 b0 = vec4( x.xy, y.xy );
      vec4 b1 = vec4( x.zw, y.zw );

      vec4 s0 = floor(b0)*2.0 + 1.0;
      vec4 s1 = floor(b1)*2.0 + 1.0;
      vec4 sh = -step(h, vec4(0.0));

      vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
      vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

      vec3 p0 = vec3(a0.xy,h.x);
      vec3 p1 = vec3(a0.zw,h.y);
      vec3 p2 = vec3(a1.xy,h.z);
      vec3 p3 = vec3(a1.zw,h.w);

      vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
      p0 *= norm.x;
      p1 *= norm.y;
      p2 *= norm.z;
      p3 *= norm.w;

      vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
      m = m * m;
      return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                    dot(p2,x2), dot(p3,x3) ) );
    }

    void main() {
      // 1. Subtle Granulation (High frequency, low amplitude)
      float grain = snoise(vNoiseCoord * 12.0);

      // 2. Macro Structure for Sunspots (Low frequency)
      float macro = snoise(vNoiseCoord * 2.5 + vec3(50.0)); 

      // 3. Base Color - Start with a clean Gold/Yellow Mix
      // Mix Core (Yellow) and Primary (Amber) slightly based on grain
      vec3 color = mix(uColorPrimary, uColorCore, grain * 0.1 + 0.4);

      // 4. Sunspots
      // Create distinct, isolated spots. 
      // Threshold high to make spots rare.
      float spotThreshold = 0.65;
      float spotMask = smoothstep(spotThreshold, spotThreshold + 0.05, macro);

      // Add 'Penumbra' (lighter edge of sunspot)
      float penumbraMask = smoothstep(spotThreshold - 0.1, spotThreshold, macro) - spotMask;

      // Apply Penumbra (Dark Orange/Brown)
      color = mix(color, uColorSecondary, penumbraMask * 0.8);
      // Apply Umbra (Dark Brown/Black)
      color = mix(color, uColorSpot, spotMask);

      // 5. Faculae (Bright patches around active regions)
      // Often appear near spots or limbs
      float faculaeMask = smoothstep(spotThreshold - 0.25, spotThreshold - 0.15, macro) * (1.0 - spotMask - penumbraMask);
      color = mix(color, vec3(1.0, 1.0, 0.9), faculaeMask * 0.3);

      // 6. Limb Darkening (Physics based)
      // The sun is brighter in the center and darker/redder at the edges.
      float viewDot = dot(vNormal, vec3(0.0, 0.0, 1.0)); // 1.0 at center, 0.0 at edge

      // Create a smooth darkening curve (Physics approximates to power of cosine)
      float limbFactor = 1.0 - pow(viewDot, 0.4); 

      // Mix towards the dark red/orange limb color
      color = mix(color, uColorSecondary, limbFactor * 0.9);

      gl_FragColor = vec4(color, 1.0);
    }
  `
);

// 2. Sun Corona Shader (Atmosphere)
// Soft, calm golden haze. Not spiky or fiery.
const SunCoronaMaterial = shaderMaterial(
  {
    uTime: 0,
    uColorInner: new Color('#FFECB3'), // Pale Yellow/White
    uColorOuter: new Color('#FF6F00'), // Amber/Orange
  },
  // Vertex
  `
    varying vec2 vUv;
    void main() {
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  // Fragment
  `
    uniform float uTime;
    uniform vec3 uColorInner;
    uniform vec3 uColorOuter;
    varying vec2 vUv;

    void main() {
      vec2 center = vec2(0.5);
      float dist = length(vUv - center) * 2.0; // 0 to 1 (edge of plane)

      if (dist > 1.0) discard;

      // Very gentle pulsation
      float pulse = 0.02 * sin(uTime * 0.8);

      // Exponential falloff for a soft "Atmospheric" look
      float alpha = 1.0 - dist;
      alpha = pow(alpha, 2.5 + pulse); 

      // Inner fade to blend with sun sphere
      float innerFade = smoothstep(0.0, 0.25, dist); 

      // Gradient color
      vec3 col = mix(uColorInner, uColorOuter, pow(dist, 1.5));

      // Reduce overall opacity for a "Gas" look
      gl_FragColor = vec4(col, alpha * 0.5 * innerFade);
    }
  `
);

extend({ SunSurfaceMaterial, SunCoronaMaterial });

interface SunProps {
  onSelect: (id: string) => void;
  isSelected: boolean;
  isPaused: boolean;
  simulationSpeed: number;
}

export const Sun: React.FC<SunProps> = ({ onSelect, isSelected, isPaused, simulationSpeed }) => {
  const meshRef = useRef<Mesh>(null);
  const surfaceMatRef = useRef<ShaderMaterial>(null);
  const coronaMatRef = useRef<ShaderMaterial>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  useFrame((state, delta) => {
    // Animate Shaders
    const time = state.clock.elapsedTime;

    if (surfaceMatRef.current) {
       surfaceMatRef.current.uniforms.uTime.value = time;
    }
    if (coronaMatRef.current) {
       coronaMatRef.current.uniforms.uTime.value = time;
    }

    if (meshRef.current && !isPaused) {
      meshRef.current.rotation.y += delta * 0.002 * simulationSpeed;
    }
  });

  return (
    <group>
      {/* 1. Main Sun Body */}
      <mesh 
        ref={meshRef}
        onPointerDown={(e) => {
          e.stopPropagation();
          clickStartRef.current = { x: e.clientX, y: e.clientY };
        }}
        onClick={(e) => {
          e.stopPropagation();
          const dx = e.clientX - clickStartRef.current.x;
          const dy = e.clientY - clickStartRef.current.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          if (distance < 5) {
            onSelect(SUN_DATA.id);
          }
        }}
        onPointerOver={() => {
          document.body.style.cursor = 'pointer';
          setHovered(true);
        }}
        onPointerOut={() => {
          document.body.style.cursor = 'auto';
          setHovered(false);
        }}
      >
        <sphereGeometry args={[SUN_DATA.size, 128, 128]} /> 

        {/* @ts-ignore */}
        <sunSurfaceMaterial 
          ref={surfaceMatRef} 
          transparent={false}
        />

        {/* Tech Style Hover Label */}
        {hovered && (
          <Html position={[0, SUN_DATA.size, 0]} zIndexRange={[100, 0]} style={{ pointerEvents: 'none' }}>
            <div className="absolute left-1/2 -translate-x-1/2 bottom-0 pb-1 flex flex-col items-center w-40">

              {/* Label Box */}
              <div className="bg-orange-900/80 backdrop-blur-md border border-yellow-500/30 px-3 py-1.5 rounded-sm shadow-[0_0_15px_rgba(255,193,7,0.3)] relative animate-fade-in-up transition-all duration-300">

                {/* Tech Corners (Yellow for Sun) */}
                <div className="absolute -top-px -left-px w-1.5 h-1.5 border-l-2 border-t-2 border-yellow-400"></div>
                <div className="absolute -top-px -right-px w-1.5 h-1.5 border-r-2 border-t-2 border-yellow-400"></div>
                <div className="absolute -bottom-px -left-px w-1.5 h-1.5 border-l-2 border-b-2 border-yellow-400"></div>
                <div className="absolute -bottom-px -right-px w-1.5 h-1.5 border-r-2 border-b-2 border-yellow-400"></div>

                {/* Scanline / Glow Overlay */}
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-yellow-400/10 to-transparent opacity-50"></div>

                <div className="flex flex-col items-center relative z-10">
                  <span className="text-yellow-50 text-xs font-bold whitespace-nowrap tracking-wider flex items-center gap-1.5" style={{ textShadow: '0 0 10px rgba(255,193,7,0.6)' }}>
                    <span className="w-1 h-1 bg-yellow-400 rounded-full animate-pulse shadow-[0_0_5px_#ffc107]"></span>
                    {SUN_DATA.name}
                  </span>
                </div>
              </div>

              {/* Connector Line */}
              <div className="w-px h-12 bg-gradient-to-b from-yellow-500/60 to-transparent mt-[-1px]"></div>

              {/* Anchor Dot */}
              <div className="w-1 h-1 bg-yellow-500/50 rounded-full"></div>
            </div>
          </Html>
        )}
      </mesh>

      {/* 2. Dynamic Corona / Atmosphere (Outer Glow) */}
      <Billboard>
         <mesh position={[0, 0, 0]}>
            <planeGeometry args={[SUN_DATA.size * 3.0, SUN_DATA.size * 3.0]} />
            {/* @ts-ignore */}
            <sunCoronaMaterial 
               ref={coronaMatRef} 
               transparent 
               depthWrite={false} 
               blending={AdditiveBlending}
            />
         </mesh>
      </Billboard>

    </group>
  );
};
